<!DOCTYPE html>
<html>
<head>
<style>
    #grid {
        display: grid;
        grid-template-columns: 30px 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr;
        grid-template-rows: 30px 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr;
        width: 600px;
        height: 400px;
        border: 1px solid #000;
    }
    #grid > div {
        padding: 2px;
        box-sizing: border-box;
        display: flex;
        align-items: center;
        justify-content: center;
    }
    #grid > input {
        width: 100%;
        height: 100%;
        border: 1px solid #000;
        box-sizing: border-box;
        font-size: 14px;
        padding: 2px;
    }
    #grid > input:focus {
        outline: none;
        background-color: #ffffcc;
    }
    #export {
        margin-top: 10px;
    }
    #csv {
        margin-top: 10px;
        width: 600px;
        height: 100px;
    }
</style>
</head>
<body>
<div id="grid"></div>
<button id="export">Export CSV</button>
<textarea id="csv"></textarea>
<script>
const cells = {};

for (let col = 0; col < 10; col++) {
    for (let row = 0; row < 10; row++) {
        const colLetter = String.fromCharCode('A'.charCodeAt(0) + col);
        const cellId = `${colLetter}${row + 1}`;
        cells[cellId] = {
            rawValue: '',
            computedValue: '0',
            dependencies: [],
            dependents: []
        };
    }
}

const grid = document.getElementById('grid');

const headerCorner = document.createElement('div');
grid.appendChild(headerCorner);

for (let col = 0; col < 10; col++) {
    const colLetter = String.fromCharCode('A'.charCodeAt(0) + col);
    const header = document.createElement('div');
    header.textContent = colLetter;
    grid.appendChild(header);
}

for (let row = 0; row < 10; row++) {
    const rowHeader = document.createElement('div');
    rowHeader.textContent = row + 1;
    grid.appendChild(rowHeader);

    for (let col = 0; col < 10; col++) {
        const colLetter = String.fromCharCode('A'.charCodeAt(0) + col);
        const cellId = `${colLetter}${row + 1}`;
        const input = document.createElement('input');
        input.id = `cell-${cellId}`;
        input.addEventListener('blur', () => {
            cells[cellId].rawValue = input.value;
            evaluateCell(cellId, []);
            updateDependents(cellId);
        });
        input.addEventListener('keydown', (e) => {
            if (e.key === 'Enter') {
                cells[cellId].rawValue = input.value;
                evaluateCell(cellId, []);
                updateDependents(cellId);
                input.blur();
            }
        });
        grid.appendChild(input);
    }
}

function evaluateCell(cellId, evaluationStack) {
    if (evaluationStack.includes(cellId)) {
        for (let id of evaluationStack) {
            cells[id].computedValue = "#CYCLE";
        }
        return;
    }
    evaluationStack.push(cellId);

    const cell = cells[cellId];
    const raw = cell.rawValue;

    if (raw.startsWith('=')) {
        const formula = raw.slice(1);
        const refs = formula.match(/([A-J](?:[1-9]|10))/g);

        if (!refs) {
            try {
                const result = eval(formula);
                cell.computedValue = typeof result === 'number' ? result.toString() : "#ERR";
            } catch (e) {
                cell.computedValue = "#ERR";
            }
        } else {
            let hasError = false;
            const replacementMap = {};

            for (const ref of refs) {
                evaluateCell(ref, evaluationStack);
                const refComputed = cells[ref].computedValue;
                if (refComputed === "#ERR" || refComputed === "#CYCLE") {
                    hasError = true;
                    break;
                }
                replacementMap[ref] = refComputed;
            }

            if (hasError) {
                cell.computedValue = "#ERR";
            } else {
                let newFormula = formula;
                for (const ref in replacementMap) {
                    newFormula = newFormula.replace(new RegExp(ref, 'g'), replacementMap[ref]);
                }
                try {
                    const result = eval(newFormula);
                    cell.computedValue = typeof result === 'number' ? result.toString() : "#ERR";
                } catch (e) {
                    cell.computedValue = "#ERR";
                }
            }
        }
    } else {
        if (raw === '') {
            cell.computedValue = '0';
        } else {
            const num = parseFloat(raw);
            cell.computedValue = isNaN(num) ? raw : num.toString();
        }
    }

    evaluationStack.pop();

    cell.dependencies = [];
    cell.dependents = [];

    if (raw.startsWith('=')) {
        const formula = raw.slice(1);
        const refs = formula.match(/([A-J](?:[1-9]|10))/g);
        if (refs) {
            for (const ref of refs) {
                cell.dependencies.push(ref);
                cells[ref].dependents.push(cellId);
            }
        }
    }
}

function updateDependents(cellId) {
    const dependents = [...cells[cellId].dependents];
    for (const dependent of dependents) {
        evaluateCell(dependent, []);
        updateDependents(dependent);
    }
}

document.getElementById('export').addEventListener('click', () => {
    let csv = '';
    for (let row = 0; row < 10; row++) {
        const rowValues = [];
        for (let col = 0; col < 10; col++) {
            const colLetter = String.fromCharCode('A'.charCodeAt(0) + col);
            const cellId = `${colLetter}${row + 1}`;
            rowValues.push(cells[cellId].computedValue);
        }
        csv += rowValues.join(',') + '\n';
    }
    document.getElementById('csv').value = csv;
});

window.sheet = {
    set: function(cellId, value) {
        const cell = cells[cellId];
        if (!cell) return;
        cell.rawValue = value;
        evaluateCell(cellId, []);
        updateDependents(cellId);
        const input = document.getElementById(`cell-${cellId}`);
        if (input) input.value = value;
    },
    get: function(cellId) {
        return cells[cellId]?.computedValue || '';
    },
    raw: function(cellId) {
        return cells[cellId]?.rawValue || '';
    }
};
</script>
</body>
</html>
